import React from "react";
import { useNavigate } from "react-router-dom";
import "./AddNew.css";

export default function AddNew({ employee }) {
  const navigate = useNavigate();

  return (
    <div className="addnew-container">
      <div className="addnew-header">
        <button className="back-btn" onClick={() => navigate(-1)}>
          ←
        </button>
        <h2>Add New</h2>
      </div>

      <p className="employee-info">
        Employee: {employee?.name} • {employee?.empld}
      </p>

      <div className="addnew-cards">

        {/* ---------------- TRAVEL CARD ---------------- */}
        <div
          className="addnew-card"
          onClick={() => navigate("/add/travel-expense")}
        >
          <h3>Travel Expense</h3>
          <p>Add new travel expense entry</p>
        </div>

        {/* ---------------- TICKET CARD ---------------- */}
        <div
          className="addnew-card"
          onClick={() => navigate("/add/ticket-expense")}
        >
          <h3>Ticket Expense</h3>
          <p>Add new ticket expense entry</p>
        </div>

        {/* ---------------- UPLOAD BILLS CARD ---------------- */}
        <div
          className="addnew-card"
          onClick={() => navigate("/add/upload-bills")}
        >
          <h3>Upload Bills</h3>
          <p>Upload your bill receipts</p>
        </div>
      </div>
    </div>
  );
}
